//*----------------------------------------------------------------------------*
//*@ 업무명   : KFA         (수신    　　　　　　　　　　　　　               )*
//*@ 화면명   : KFA04151000 (구속성예금 조회                                  )*
//*@ 호출번호 : [04-10-151]                                                    *
//*@ 처리개요 : 구속성예금조회                                                 *
//*----------------------------------------------------------------------------*
//*@ 성명  :  일자  :  변　경　내　용　　　　　　　　　　　　　　              *
//*----------------------------------------------------------------------------*
//* 하상구 :20150401: KB-PIN 활용 확대개발 　　　　　　　　　　　              *
//*   〃   :20150411: 1개월만기도래/B2B정보 추가 및 안내메시지 변경            *
//*   〃   :20150430: 고객식별자 직접입력 (KHC_queryKbpinCustName)             *
//*   〃   :20150608: KAA0490041 호출결과의 고객고유번호 사용                  *
//*        :        : - KB-PIN 직접입력에 의한 거래 후 선불카드조회 클릭 시    *
//*        :        :   고객번호 링크 처리 위함                                *
//*   〃   :20160219: 법인관련인에 임원 제외 따른 업무처리                     *
//*        :        : - 명칭변경 : 법인관련인 → 관련법인                      *
//* 김현종 :20200101: 구속행위점검대상 신용평점 변경 적용                      *
//* 김현종 :20200325: 구속성 검증대상 구분(표) 추가(기존 안내메세지 숨김)      *
//* 남병천 :20250219: 직원용 단말화면 Re-Design 구축 프로젝트                  *
//*                 : 구속성예금 사전조회 조회결과 > 수신계좌 및 판매현황 링크 조회버튼으로 변경
//*                 : KB-PIN 검색버튼 삭제 및 에디트박스 내 검색기능 사용      *
//*                 : 하단 검색버튼 링크텍스트로 변경                          *
//*                 : 구속행위 검증대상 구분 팝업 제거 및 화면내 출력          *
//*----------------------------------------------------------------------------*

/* 에디트박스 색상 적용불가(UI/UX표준) - 직원용 단말화면 Re-Design 구축 프로젝트
rstrctnAcno1.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno1_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno1_2.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno2.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno2_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno2_2.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno3.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno3_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno3_2.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno4.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno5.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno5_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno5_2.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno6.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno6_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno7.ForeColor    =  GetRGBValue (0,0,255);
rstrctnBuho7.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno7_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnBuho7_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno8.ForeColor    =  GetRGBValue (0,0,255);
rstrctnBuho8.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno8_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnBuho8_1.ForeColor  =  GetRGBValue (0,0,255);
rstrctnAcno9.ForeColor    =  GetRGBValue (0,0,255);
rstrctnAcno10.ForeColor   =  GetRGBValue (0,0,255);
rstrctnAcno11.ForeColor   =  GetRGBValue (0,0,255);
rstrctnTPrdctYna.ForeColor  =  GetRGBValue (0,0,255); 
snrgMgtNo.ForeColor  =  GetRGBValue (0,0,255); // 2404XX //수신성기여등록 추가
*/

//2021.03.25 구속성 검증대상 구분(표) 추가(기존 안내메세지 숨김) 
//GroupBox_Msg.BackColor  =  GetRGBValue (255,255,0);

//2021.03.25 구속성 검증대상 구분표 버튼색상 변경
Button3.BackColor = $c.iz.data.getRGBValue(255, 0, 0);

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {};

scwin.OnSendKey = async function() {
    //여기에 구현코드를 삽입하세요.
    $c.iz.tran.setTranID("KFA0415140");
    $c.iz.tran.lockScreen();
    await $c.iz.tran.ASend();
};

/**----------------------------------------------
* @수정내역: 20250218 남병천  구속성 검증대상 팝업 화면내 출력으로 변경
*                             조회결과 상단 안내문구, 정액적립식, 정액적립식 외 재예치가능잔액 그룹박스 색상 적용
*                             직원용 단말화면 Re-Design 구축 프로젝트
----------------------------------------------**/
scwin.OnEndTran = function() {
    //조회거래 정상 수행완료 여부 확인

    if ($c.iz._tran.tranId == "KFA0415140" && $c.iz._tran.bError == false) {
        // 2014.03.01 : 법인 검증기준 추가

        GroupBox3.show('');
        //2021.03.25 구속성 검증대상 구분(표) 추가(기존 안내메세지 숨김) 
        text_Msg.setValue("");
        if (lnbzCustIdnfr.getValue() == "") {
            lnbzRelshp.setValue("");
        } else {
            if (lnbzRelshpDstcd.getValue() == "01") {
                lnbzRelshp.setValue("본인");
            }
            if (lnbzRelshpDstcd.getValue() == "99") {
                lnbzRelshp.setValue("관련법인");
            }
        }
        if (rstrctnTPrdctYna_h.getValue() == "1") {
            rstrctnTPrdctYna.setValue("구매/충전");
        } else {
            rstrctnTPrdctYna.setValue("");
        }

        // CHG START (20150411) 하상구 : 1개월만기도래/B2B정보 추가 및 안내메시지 변경 ------------------

        // 2016.12.02 안내메세지 일괄 변경  이경오 
        //-- 1) 1개월내 여신 존재
        if (inbzTagetDstic.getValue() == "1") {
            // 조건 1 : 1:여신업무(가계) 인 경우
            if (debtconddstcd.getValue() == "1") {
                //text_Msg.Value = "☞ 1개월 이내 신용등급 7등급이하 가계대출이 취급(기한연장 포함) 되어 수신 신규 불가합니다."; 

                //text_Msg.Value = "☞ 1개월 이내 당행 신용평가등급 7등급 이하 또는 신용평가회사 신용평점 하위 10% 이하 개인의 가계대출이 취급(기한연장 포함) 되어 \n"

                //             + "    수신 신규 불가합니다.";  

            }

            // 조매 1 : 6:여신업무(기업) 인 경우
            if (debtconddstcd.getValue() == "6") {
                //text_Msg.Value = "☞ 1개월 이내 중소기업 여신이 취급되어 수신 신규/판매 불가합니다.";

            }

            // 조매 7 : 7:KB셀러론 약정인 경우 2018.07.30
            if (debtconddstcd.getValue() == "7") {
                //text_Msg.Value = "☞ 1개월 이내 KB셀러론(한도 약정)이 취급되어 수신 신규/판매 불가합니다.";

            }

            // 조매 8 : 8:KB상생플러스론 약정인 경우 
            if (debtconddstcd.getValue() == "8") {
                //text_Msg.Value = "☞ 1개월 이내 KB상생플러스론(한도 약정)이 취급되어 수신 신규/판매 불가합니다.";

            }

            // 조매 1 : 2:B2B 인 경우
            if (debtconddstcd.getValue() == "2") {
                //text_Msg.Value = "☞ 1개월 이내 B2B여신(외매채 판매기업 한도 약정)이 취급되어 수신 신규/판매 불가합니다.";

            }

            // 조매 1 : 3:개인여신심사건 인 경우
            if (debtconddstcd.getValue() == "3") {
                if (debtprdctdstic.getValue() == "1") {
                    //text_Msg.Value = "☞ 1개월 이내 신용등급 7등급이하 가계대출 창구기한연장 예정으로 수신 신규/판매 불가합니다.";

                    //text_Msg.Value = "☞ 1개월 이내 당행 신용평가등급 7등급 이하 또는 신용평가회사 신용평점 하위 10% 이하 개인의 가계대출 창구기한연장 예정으로 \n"

                    //               + "    수신 신규/판매 불가합니다.";

                } else {
                    //text_Msg.Value = "☞ 1개월 이내 신용등급 7등급이하 가계대출 신규(증액)취급 예정으로 수신 가입시 대출실행이 제한될 수 있습니다.";

                    //text_Msg.Value = "☞ 1개월 이내 당행 신용평가등급 7등급 이하 또는 신용평가회사 신용평점 하위 10% 이하 개인의 가계대출 신규(증액)취급 예정으로 \n"

                    //              + "    수신 가입시 대출실행이 제한될 수 있습니다.";    

                }
            }

            // 조매 1 : 4:소호심사진행건 인 경우
            // 조매 1 : 5:기업심사진행건 인 경우
            if (debtconddstcd.getValue() == "4" || debtconddstcd.getValue() == "5") {
                // 해당 진행건이 기한연장인 경우
                if (debtprdctdstic.getValue() == "1") {
                    //text_Msg.Value = "☞ 1개월 이내 중소기업(SOHO포함) 여신 기한연장 심사승인 완료 하였으므로  수신 신규/판매 불가합니다.";  

                } else {
                    //text_Msg.Value = "☞ 1개월 이내 중소기업(SOHO포함) 여신 심사진행건이 존재하므로 수신 신규/판매시 대출실행이 제한될 수 있습니다.";  

                }
            }
            //text_Msg.Value = "☞ 1개월 내 여신 실행하였으므로 예금 신규 불가합니다.";

        }

        //-- 2) 1개월이내 여신은 없으나 1개월이내 만기도래하는 여신 존재
        if (inbzTagetDstic.getValue() == "2") {
            // 금일 만기도래 여신 중 1: 가계대출인 경우
            if (mangicheridstcd.getValue() == "1") {
                //text_Msg.Value = "☞ 금일 만기도래(경과)된 창구기한연장 가계대출이 존재합니다. 수신가입시 대출실행이 제한될 수 있습니다.";

            }

            // 금일 만기도래 여신 중 2: 기업대출 , 6: B2B인 경우
            if (mangicheridstcd.getValue() == "2" || mangicheridstcd.getValue() == "6") {
                //text_Msg.Value = "☞ 조회기준일에 만기도래(경과)된 기업여신이 존재합니다. 수신 신규/판매 당일에는 여신실행(기한연장 포함)이 제한될 수 있습니다.";

            }
            // text_Msg.Value = "☞ 1개월 내 여신취급이 예상되므로 관련여신 확인하여 안내 바랍니다.";

            //-- 항목명 변경 : 여신실행(예정)금액 --> 만기도래(예정)금액
            Text_LnAmt.hide();
            Text_ExAmt.show('');
            Text_ExAmt.setPosition(Text_LnAmt.X, Text_LnAmt.Y);

            //-- 항목명 변경 : 여신실행(예정)일자 --> 만기도래일자
            Text_LnYmd.hide();
            Text_ExYmd.show('');
            Text_ExYmd.setPosition(Text_LnYmd.X, Text_LnYmd.Y);
        }

        //-- 3) 1개월이내 여신과 1개월이내 만기도래하는 여신 모두 없음
        if (inbzTagetDstic.getValue() != "1" && inbzTagetDstic.getValue() != "2") {
            //-- ① 법인관련고객 => 2016.02.19  법인대표자로 변경
            //if (cno_dstcd.Data == "법인관련고객") {
            if (cno_dstcd.getValue() == "법인대표자") {
                //text_Msg.Value = "☞ 예금신규 시 1개월 이내 관련 중소기업(SOHO포함) 여신 및 본인의 신용등급 7등급 이하 가계여신 취급이 일체 불가하므로 필수 안내 바랍니다."; 

                //text_Msg.Value = "☞ 예금신규 시 1개월 이내 관련 중소기업(SOHO포함) 여신 및 본인의 당행 신용평가등급 7등급 이하 또는 신용평가회사 신용평점 하위 10% 이하 \n"

                //               + "    개인의 가계여신 취급이 일체 불가하므로 필수 안내 바랍니다."; 

                // text_Msg.Value = "☞ 예금신규 시 1개월내 본인 및 관련법인의 여신취급이 불가함을 안내바랍니다.";

            }

            //-- ② 순수개인고객 또는 중소기업고객
            //if (cno_dstcd.Data != "법인관련고객"  &&  cno_dstcd.Data != "") {
            if (cno_dstcd.getValue() != "법인대표자" && cno_dstcd.getValue() != "") {
                //text_Msg.Value = "☞ 예금신규 시 1개월 이내 본인의 중소기업(SOHO포함) 여신 및 신용등급 7등급 이하 가계여신 취급이 일체 불가하므로 필수 안내 바랍니다.";

                //text_Msg.Value = "☞ 예금신규 시 1개월 이내 본인의 중소기업(SOHO포함) 여신 및 당행 신용평가등급 7등급 이하 또는 신용평가회사 신용평점 하위 10% 이하 \n"

                //               + "    개인의 가계여신 취급이 일체 불가하므로 필수 안내 바랍니다.";

                // text_Msg.Value = "☞ 예금신규 시 1개월내의 여신(가계여신의 경우 신용등급 7등급 이하)취급이 불가함을 안내 바랍니다.";

            }

            //-- ③ 구속성 검증대상 고객 아님
            if (cno_dstcd.getValue() == "") {
                //text_Msg.Value = "☞ 구속행위 검증 대상이 아니므로 예금신규 가능합니다."; 

            }
        }

        //-- B2B이면 항목명 변경 : 여신계좌번호 → 사업자번호
        if (lnbzInfoDstic.getValue() == "2 - Ｂ２Ｂ업무") {
            Text_Acno.hide();
            Text_Bzno.show('');
            Text_Bzno.setPosition(Text_Acno.X, Text_Acno.Y);
        }

        //-- B2B이면 항목명 변경 : 여신계좌번호 → 사업자번호(2018.0816)
        if (lnbzInfoDstic.getValue() == "7 - 셀러론업무") {
            Text_Acno.hide();
            Text_Bzno.show('');
            Text_Bzno.setPosition(Text_Acno.X, Text_Acno.Y);
        }


        //-- 조회구분 1-구속성예금사전조회, 2-구속성예금 재예치 가능금액 조회
        if (jo_gbn.getValue() == "1") {
            GroupBox3.show('');
            //GroupBox_Msg.Visible = true;	     
            GroupBox_Msg.Fold = false;
            GroupBox11.hide();

            //2021.03.25 구속성 검증대상 구분표 팝업
            // 팝업제거 및 화면내 출력 - 직원용 단말화면 Re-Design 구축 프로젝트
            //Popup("KFA04999B99","DATALINK");
        } else {
            GroupBox3.hide();
            //GroupBox_Msg.Visible = false;        
            GroupBox_Msg.Fold = true;
            GroupBox11.show('');

            // 조회결과 상단 메시지
            GroupBox131.setDisabled(false); // 색상 출력하기 위해 Enabled처리
            // 정액적립식, 정액적립식 외 재예치가능잔액 그룹박스
            GroupBox109.setDisabled(false); // 색상 출력하기 위해 Enabled처리
            GroupBox110.setDisabled(false); // 색상 출력하기 위해 Enabled처리
        }

        // CHG END   (20150411) 하상구 : 1개월만기도래/B2B정보 추가 및 안내메시지 변경 ------------------

    }
};

/**----------------------------------------------
* @수정내역: 20250218 남병천  안내메시지 기본 출력(GroupBox_Msg)
*                             직원용 단말화면 Re-Design 구축 프로젝트
----------------------------------------------**/
scwin.OnInitScreen = function() {
    //여기에 구현코드를 삽입하세요.
    GroupBox3.hide();
    //GroupBox_Msg.Visible = false;
    text_Msg.setValue("");
    GroupBox11.hide();
    Text_Acno.show('');
    Text_Bzno.hide();
    Text_LnAmt.show('');
    Text_ExAmt.hide();
    Text_LnYmd.show('');
    Text_ExYmd.hide();
    date.setValue($c.user.getUserProfile('nowBzoprYmd'));

    //-- 구속성예금 팝업창 (KHC04999A99) 호출 시 자동 실행
    if (rstrPopCallYn.getValue() == "1" &&
        jo_gbn.getValue() == "1" &&
        custIdnfr.getValue() != "") {
        scwin.OnSendKey();
    }
};

scwin.UnLockScreen = function() {
