// ADD START (20150401) 하상구 : 고객정보번호활용확대 전산개발 ------------------
scwin.custIdnfr_OnValidate = function(info) {
    // KB-PIN번호 입력시 hidden 주민번호 clear                
    cno.setValue();
    custnm.setValue();

    // 고객명 추출 (ADD - 20150430 하상구)
    //KHC_queryKbpinCustName(custIdnfr,custnm);

    if (custIdnfr.getValue().length > 0) {
        $c.iz.tran.setTranID("KAA0490041");
        $c.iz.tran.setInFDData("KAA0490041", "custIdnfr", custIdnfr.getValue());
        $c.iz.tran.setInFDData("KAA0490041", "custMgtNo", "00000");
        $c.iz.tran.WaitSend();
        if ($c.iz._tran.bError == false) {
            $c.iz.data.message("");
            custnm.setValue($c.iz.tran.getOutMultiDataByIndex("screen", "dtalsCustGrid/dataBook", "custnm", 0));
            // 20150608 : 고객번호 링크
            cno.setValue($c.iz.tran.getOutMultiDataByIndex("screen", "dtalsCustGrid/dataBook", "cuniqno", 0));
        } else {
            custnm.setValue();
            cno.setValue();
        }
    } else {
        custnm.setValue();
        $c.iz.data.message("고객번호를 확인해주세요");
    }

    //if (custIdnfr.Data != "") {     (DEL) 20150430 하상구

    //    Button1_OnClick();          (DEL) 20150430 하상구 

    //}                               (DEL) 20150430 하상구 

};
// ADD END (20150401) 하상구 : 고객정보번호활용확대 전산개발 ----------------------


