scwin.LinkText_rstrctnTPrdctYna_OnClick = function(e) {
    if (rstrctnTPrdctYna.getValue() != "") {
        if (this.IsNextCard() == true) {
            //alert ("card link" +  cno.Data,"카드사");
            this.CardLinkSetData("custCd", '05');
            this.CardLinkSetData("ssno", cno.getValue());
            ScreenOpenCard("GEB01008M01");
        } else {
            Link.custCd = "05";
            Link.ssno = cno.getValue();
            $c.iz.screen.screenOpen("KBA04109000", "DATALINK");
        }
    }
};

